var StripeEngine = class {
  stripe;
  constructor(secretKey) {
    this.stripe = new stripe_esm_worker_default(secretKey, { apiVersion: "2023-10-16" });
  }
  async createCustomer(tenantId, email) {
    const customer = await this.stripe.customers.create({
      email,
      metadata: { tenantId }
    });
    return customer.id;
  }
  async createCheckoutSession(planId, customerId, successUrl, cancelUrl) {
    return await this.stripe.checkout.sessions.create({
      mode: "subscription",
      customer: customerId,
      line_items: [{ price: planId, quantity: 1 }],
      success_url: successUrl,
      cancel_url: cancelUrl
    });
  }
  async createBillingPortal(customerId, returnUrl) {
    return await this.stripe.billingPortal.sessions.create({
      customer: customerId,
      return_url: returnUrl
    });
  }
  async attachPaymentMethod(customerId, paymentMethodId) {
    await this.stripe.paymentMethods.attach(paymentMethodId, { customer: customerId });
    await this.stripe.customers.update(customerId, {
      invoice_settings: { default_payment_method: paymentMethodId }
    });
  }
  async getSubscription(subscriptionId) {
    return await this.stripe.subscriptions.retrieve(subscriptionId);
  }
  async cancelSubscription(subscriptionId) {
    return await this.stripe.subscriptions.del(subscriptionId);
  }
  async reportUsage(subscriptionItemId, quantity) {
    return await this.stripe.subscriptionItems.createUsageRecord(subscriptionItemId, {
      quantity,
      action: "increment"
    });
  }
};
