function resolveBestPlanRule(basePlanRules, context2) {
  if (!basePlanRules.length)
    return null;
  for (const rule of basePlanRules) {
    const cond = rule.conditions_json ?? {};
    const out = rule.output_json ?? {};
    if (cond.min_employees != null && context2.employeeCount < cond.min_employees)
      continue;
    if (cond.max_employees != null && context2.employeeCount > cond.max_employees)
      continue;
    if (cond.country && context2.country && cond.country !== context2.country)
      continue;
    if (cond.company_type_code && context2.companyTypeCode && cond.company_type_code !== context2.companyTypeCode)
      continue;
    if (cond.business_size && context2.businessSize && cond.business_size !== context2.businessSize)
      continue;
    return {
      planCode: out.plan_code ?? rule.rule_key ?? "custom",
      planName: out.plan_name ?? "Custom Plan",
      monthlyPrice: out.price_monthly ?? 0,
      yearlyPrice: out.price_yearly ?? 0,
      includedSeats: out.included_seats ?? 5,
      includedModules: out.included_modules ?? ["hr", "accounting", "crm"],
      currency: out.currency ?? "AED"
    };
  }
  return null;
}
