async function getRevenueAnalytics(request, adminSupabase) {
  const url = new URL(request.url);
  const days = parseInt(url.searchParams.get("days") || "30", 10);
  const since = new Date(Date.now() - days * 864e5).toISOString();
  const [subsRes, paymentsRes, plansRes, companiesRes] = await Promise.all([
    adminSupabase.from("company_subscriptions").select("plan_code, status, gateway, billing_interval, created_at"),
    adminSupabase.from("payment_events").select("gateway, amount, currency, status, created_at").gte("created_at", since).in("status", ["success", "completed"]),
    adminSupabase.from("subscription_plans").select("code, price_monthly, price_yearly, currency"),
    adminSupabase.from("companies").select("id, created_at").gte("created_at", since)
  ]);
  const subs = subsRes.data || [];
  const payments = paymentsRes.data || [];
  const plans = plansRes.data || [];
  const newCompanies = companiesRes.data || [];
  const planPrices = new Map(plans.map((p) => [p.code, p]));
  let mrr = 0;
  const planBreakdown = {};
  for (const sub of subs) {
    if (sub.status !== "active")
      continue;
    const plan = planPrices.get(sub.plan_code);
    if (!plan)
      continue;
    const monthlyValue = sub.billing_interval === "yearly" ? (plan.price_yearly || plan.price_monthly * 10) / 12 : plan.price_monthly;
    mrr += monthlyValue;
    if (!planBreakdown[sub.plan_code])
      planBreakdown[sub.plan_code] = { count: 0, mrr: 0 };
    planBreakdown[sub.plan_code].count++;
    planBreakdown[sub.plan_code].mrr += monthlyValue;
  }
  const gatewayDist = {};
  for (const p of payments) {
    gatewayDist[p.gateway] = (gatewayDist[p.gateway] || 0) + (p.amount || 0);
  }
  const statusDist = {};
  for (const sub of subs) {
    statusDist[sub.status] = (statusDist[sub.status] || 0) + 1;
  }
  return jsonResponse({
    period_days: days,
    mrr: Math.round(mrr * 100) / 100,
    arr: Math.round(mrr * 12 * 100) / 100,
    total_subscriptions: subs.length,
    active_subscriptions: subs.filter((s) => s.status === "active").length,
    new_companies: newCompanies.length,
    revenue_by_gateway: gatewayDist,
    subscription_status: statusDist,
    plan_breakdown: planBreakdown,
    payments_in_period: payments.length
  });
}
